sql:
SELECT COUNT(*)
FROM team_awards
WHERE team_id = 1;

SELECT DISTINCT T1.player_name
FROM players AS T1
JOIN player_awards AS T2 ON T1.player_id = T2.player_id;

SELECT player_name
FROM players
WHERE player_id > 5;

SELECT players.player_name, player_awards.award_name
FROM players
JOIN player_awards ON players.player_id = player_awards.player_id;

SELECT DISTINCT p.player_name
FROM players p
JOIN player_awards a ON p.player_id = a.player_id;

SELECT total_prize_pool
FROM series
WHERE series_id = 0;

SELECT pp.*
FROM player_performance pp
WHERE pp.avg_score > (
    SELECT AVG(avg_score) 
    FROM player_performance
);

SELECT player_name, years_active
FROM players
WHERE player_id = 0;

SELECT players.player_name, player_performance.avg_score
FROM players
JOIN player_performance ON players.player_id = player_performance.player_id;

external_knowledge:
- 'Carry' refers to players who are expected to carry their team to victory through their individual skill; 
- 'accolades' and 'glittering awards' refer to the awards_win count in the query, which must be greater than zero;
- 'luminous performances' metaphorically represents the players' average scores;
- 'compared to their team's brilliance' refers to the comparison between the individual player's average score and the team's average score;
- 'celestial expanse of their career' metaphorically represents the number of series the player has attended, which must be greater than zero.
